require 'cjson'
-- deserializes cookies stored in strings with keys
function openresty_sess.load(k)
  local v = ngx.var[k] or '' -- default to empty table

  -- deserialize Lua tables that are stored as text
  if type(v) == 'string' then
    return load('return '..v)() end

  -- handle deserialization errors: use empty table in this case
  -- this may break some features of our app!
  -- do not do this at production:
  return setmetatable({}, {__index=function() return {} end})
end

function openresty_sess.save(k, v)
    local v = cjson.encode(v or {})

    ngx.header['Set-Cookie'] =
      openresty_sess._cookiename..'=' ..ngx.escape_uri(v) .. '; '
      .. 'Path=/'..'; Expires='
      .. ngx.cookie_time(openresty_sess._maxage)
end

